import React, { useState } from "react";
import VerifyOTP from "./VerifyOTP";

export default function UserRegister({ closeModal }) {
  const BASE_URL = "http://localhost:8086";

  const [formData, setFormData] = useState({
    username: "",
    name: "",
    email: "",
    password: "",
    confirmPassword: "",
  });

  const [error, setError] = useState("");
  const [goOTP, setGoOTP] = useState(false);

  const handleChange = (e) => {
    setFormData({...formData, [e.target.name]: e.target.value});
  };

  const validate = () => {
    if (!/^[iI][tT]\d{8}@my\.sliit\.lk$/.test(formData.email)) {
      return "Invalid SLIIT email";
    }
    if (formData.password !== formData.confirmPassword) {
      return "Passwords do not match";
    }
    return "";
  };

  const sendOTP = async () => {
    const err = validate();
    if (err) {
      setError(err);
      return;
    }

    try {
      const res = await fetch(`${BASE_URL}/user/send-otp`, {
        method: "POST",
        headers: {"Content-Type": "application/json"},
        body: JSON.stringify({ email: formData.email }),
      });

      const data = await res.text();

      if (res.ok) {
        // ✅ store temporarily
        localStorage.setItem("registerData", JSON.stringify(formData));
        setGoOTP(true);
      } else {
        setError(data);
      }
    } catch {
      setError("Server error");
    }
  };

  if (goOTP) {
    return <VerifyOTP email={formData.email} closeModal={closeModal} />;
  }

  return (
    <div className="p-8 bg-white/20 rounded-xl text-white">
      <h2 className="text-xl mb-4">Student Registration</h2>

      <input name="username" onChange={handleChange} placeholder="Username" className="input"/>
      <input name="name" onChange={handleChange} placeholder="Full Name" className="input"/>
      <input name="email" onChange={handleChange} placeholder="Email" className="input"/>
      <input type="password" name="password" onChange={handleChange} placeholder="Password" className="input"/>
      <input type="password" name="confirmPassword" onChange={handleChange} placeholder="Confirm Password" className="input"/>

      {error && <p className="text-red-300">{error}</p>}

      <button onClick={sendOTP} className="btn-blue">
        Register (Send OTP)
      </button>
    </div>
  );
}
